def word_search(board, word):
    if not board or not board[0]:
        return False
    if not word:
        return True

    rows = len(board)
    cols = len(board[0])
    word_len = len(word)

    # 8 directions: (row_delta, col_delta)
    directions = [
        (0, 1),   # Right
        (0, -1),  # Left
        (1, 0),   # Down
        (-1, 0),  # Up
        (1, 1),   # Down-Right
        (1, -1),  # Down-Left
        (-1, 1),  # Up-Right
        (-1, -1)  # Up-Left
    ]

    def check_straight_line(r, c, dr, dc):
        for k in range(word_len):
            curr_r = r + k * dr
            curr_c = c + k * dc

            # Check bounds
            if not (0 <= curr_r < rows and 0 <= curr_c < cols):
                return False

            # Check character match
            if board[curr_r][curr_c] != word[k]:
                return False
        return True

    for r in range(rows):
        for c in range(cols):
            # Optimization: Only start search if the first character matches
            if board[r][c] == word[0]:
                for dr, dc in directions:
                    if check_straight_line(r, c, dr, dc):
                        return True

    return False
